3_real_world_example.code:
//  Pure — same inputs always produce same output, no side effects
function calculateTax(price, taxRate) {
  return Math.round(price * taxRate * 100) / 100;
}

console.log(calculateTax(100, 0.15)); // 15  — always
console.log(calculateTax(100, 0.15)); // 15  — always

//  Impure — reads external state (taxRate could change)
let taxRate = 0.15;
function impureTax(price) {
  return price * taxRate; // depends on external variable
}

//  Impure — has a side effect (mutates external array)
const log = [];
function logAndCalc(price, rate) {
  log.push({ price, rate }); // side effect!
  return price * rate;
}

6_edge_case.code:
//  Impure — different result every call even with same arguments
function generateId(prefix) {
  return `${prefix}-${Math.random().toString(36).slice(2)}`;
}

//  Pure alternative — inject randomness as a parameter
function generateIdPure(prefix, random) {
  return `${prefix}-${random.toString(36).slice(2)}`;
}
// Now fully testable: generateIdPure('user', 0.12345) always returns the same ID
